# traceability_register.py
# Minimal traceability register with stale-link detection

import json
from dataclasses import dataclass, field, asdict
from typing import List, Optional
from pathlib import Path

@dataclass
class TraceEntry:
    proto_id: str
    spec_id: str
    ticket_ids: List[str] = field(default_factory=list)
    test_case_ids: List[str] = field(default_factory=list)
    status: str = "active"  # active | stale | deprecated
    stale_reason: Optional[str] = None

class TraceabilityRegister:
    def __init__(self, path: str):
        self.path = Path(path)
        self.entries: List[TraceEntry] = []
        if self.path.exists():
            self._load()

    def _load(self):
        data = json.loads(self.path.read_text())
        self.entries = [TraceEntry(**e) for e in data["entries"]]

    def save(self):
        data = {"entries": [asdict(e) for e in self.entries]}
        self.path.write_text(json.dumps(data, indent=2))

    def add(self, entry: TraceEntry):
        self.entries.append(entry)

    def mark_stale(self, proto_id: str, reason: str):
        """Called when a prototype frame is revised post-sign-off."""
        affected = [e for e in self.entries if e.proto_id == proto_id]
        for e in affected:
            e.status = "stale"
            e.stale_reason = reason
        return affected

    def impacted_tickets(self, proto_id: str) -> List[str]:
        """Return all ticket IDs that depend on a given prototype frame."""
        tickets = []
        for e in self.entries:
            if e.proto_id == proto_id:
                tickets.extend(e.ticket_ids)
        return list(set(tickets))

    def stale_entries(self) -> List[TraceEntry]:
        return [e for e in self.entries if e.status == "stale"]


# Example usage
register = TraceabilityRegister("trace_register.json")
register.add(TraceEntry(
    proto_id="PROTO-search-results-agentloading",
    spec_id="SPEC-SEARCH-001",
    ticket_ids=["ENG-441", "ENG-442", "ENG-445"],
    test_case_ids=["TC-SEARCH-001", "TC-SEARCH-002"]
))
register.save()

# When prototype frame is revised:
stale = register.mark_stale(
    "PROTO-search-results-agentloading",
    reason="Loading state redesigned in sprint 4 review"
)
print(f"Stale entries: {[e.spec_id for e in stale]}")
print(f"Tickets to update: {register.impacted_tickets('PROTO-search-results-agentloading')}")

