# ci_trace_check.py
# Run in CI to catch stale traceability links before merging design changes

import json
import sys
from pathlib import Path

def load_register(path: str) -> list[dict]:
    return json.loads(Path(path).read_text())["entries"]

def load_figma_export(path: str) -> set[str]:
    """Extract proto_ids from Figma JSON export."""
    data = json.loads(Path(path).read_text())
    proto_ids = set()
    for frame in data.get("frames", []):
        if "proto_id" in frame.get("annotations", {}):
            proto_ids.add(frame["annotations"]["proto_id"])
    return proto_ids

def check_stale(register_path: str, figma_export_path: str) -> int:
    entries = load_register(register_path)
    active_proto_ids = load_figma_export(figma_export_path)

    errors = []
    for entry in entries:
        if entry["status"] == "active":
            if entry["proto_id"] not in active_proto_ids:
                errors.append(
                    f"STALE: {entry['proto_id']} referenced in "
                    f"{entry['spec_id']} but no longer in Figma export"
                )

    if errors:
        print("Traceability check FAILED:")
        for err in errors:
            print(f"  {err}")
        return 1

    print(f"Traceability check passed: {len(entries)} entries validated")
    return 0

if __name__ == "__main__":
    exit(check_stale("trace_register.json", "figma_export.json"))
